<script setup lang="ts">import{computed,onMounted,ref}from'vue';import{useMemoriesStore}from'../stores/memories';import type{MemoryEntry}from'@developer-memory/shared-types';const props=defineProps<{projectId:string}>(),store=useMemoriesStore(),title=ref(''),content=ref(''),type=ref<MemoryEntry['type']>('NOTE'),query=ref(''),filter=ref('');const shown=computed(()=>store.items.filter(m=>(!query.value||`${m.title} ${m.content} ${m.tags.join(' ')}`.toLowerCase().includes(query.value.toLowerCase()))&&(!filter.value||m.type===filter.value)));onMounted(()=>store.load(props.projectId));async function create(){if(!title.value.trim()||!content.value.trim())return;await store.create(props.projectId,{title:title.value,content:content.value,type:type.value});title.value='';content.value=''}</script>
<template><section class="phase-panel"><div class="tab-heading"><div><p class="eyebrow">Project knowledge</p><h2>Memories</h2></div></div><div v-if="store.error" class="alert error-alert">{{store.error}}</div><form class="memory-form" @submit.prevent="create"><select v-model="type"><option v-for="t in ['NOTE','DECISION','BUG','TASK','SOLUTION','QUESTION','OUTCOME']" :key="t">{{t}}</option></select><input v-model="title" maxlength="200" placeholder="Title" required><textarea v-model="content" maxlength="20000" placeholder="What should be remembered?" required></textarea><button class="button primary">Save Memory</button></form><div class="file-filters"><input v-model="query" placeholder="Search memories…"><select v-model="filter"><option value="">All types</option><option v-for="t in ['NOTE','DECISION','BUG','TASK','SOLUTION','QUESTION','OUTCOME']" :key="t">{{t}}</option></select></div><article v-for="m in shown" :key="m.id" class="memory-card"><div><span class="record-type">{{m.type}} · {{m.status}}</span><h3>{{m.title}}</h3><p>{{m.content}}</p><small>{{new Date(m.createdAt).toLocaleString()}} <template v-if="m.relativeFilePath">· {{m.relativeFilePath}}</template></small></div><div class="record-actions"><button v-if="m.status==='OPEN'" @click="store.action(projectId,m.id,'resolve')">Resolve</button><button @click="store.action(projectId,m.id,'archive')">Archive</button></div></article></section></template>
